{{#css:
.aaa{
    pointer-events: none;
    cursor: default;
}
.rocom_canlearn_box{
background:#fff;
align-items:center;
height:auto;
border-radius:50px;
}
.rocom_canlearn_img_box{
margin: 5px 10px 5px 10px;
border-radius:20px;
display: inline-block;
transition: background 0.3s;
}
.rocom_canlearn_img_box:hover {
background: #dbdbdb; /* 背景变暗 */
}
.rocom_canlearn_margin_Box{
margin: 20px 0px 0px 40px;
}
.rocom_skill_template_box{
background:#fff;
display:flex;
align-items:center;
height:300px;
border-radius:50px;
}
.rocom_skill_template_skillIcon{
    margin: 0px 50px 0px 40px;
}
.rocom_skill_template_rightBox{
    margin-bottom: 15px;
}
.rocom_skill_template_skillName{
    font-size: 30px;
    font-weight: 900;
    margin-bottom:5px;
}
.rocom_skill_template_txtBox{
    display: flex;
    background:#292d2e;
    border-radius:30px;
    height:62px;
    width:120%;
    margin-bottom:9px;
}
.rocom_skill_template_txtBox div{
    display: grid;
    justify-items: center;
    align-items:center;
    align-content:center;
    color:#fff;
    margin-left:15px;
    font-weight:900;
}

.rocom_skill_template_skillConsume_box span{
    display:flex;
    width:25px;
    height:25px;
    color: #000;
    font-weight: 900;
    background-size:cover;
    background-position:center;
    justify-content:center;
    align-items:center;
background-repeat:no-repeat;
}
.rocom_skill_template_skillEffect{
color:#485368;
}
.rocom_skill_template_skillDescribe{
color:#91908b;
}
.rocom_skill_template_skillEffect,
.rocom_skill_template_skillDescribe{
font-size:15px;
font-weight:900;
margin-top:15px;
}
.rocom_skill_template_skillPower{
    margin-left: 80px!important;
    position: relative;
}
.rocom_skill_template_skillPower::before{
content:"";
position:absolute;
background:#fff;
width:2px;
height:45px;
left:-30px;
}
}}
